// ===== CONFIGURATION =====
const PROJECT_NAME = 'YOUR_PROJECT_NAME';
const TIMEZONE = 'Europe/Warsaw';
// =========================

const items = $input.all();
const allEntries = [];
const dailyGroups = {};
const monthsSet = new Set();

for (const item of items) {
  const d = item.json;
  if (d.name !== PROJECT_NAME) continue;
  if (!d.start || !d.stop || d.duration < 0) continue;
  const startDt = DateTime.fromISO(d.start).setZone(TIMEZONE);
  const stopDt = DateTime.fromISO(d.stop).setZone(TIMEZONE);
  const month = startDt.toFormat('yyyy-MM');
  const dateStr = startDt.toFormat('yyyy-MM-dd');
  const duration = d.duration;
  const hours = Math.floor(duration / 3600);
  const minutes = Math.floor((duration % 3600) / 60);

  const entry = {
    description: d.description || '',
    project: d.name || 'No project',
    start_date: dateStr,
    start_time: startDt.toFormat('HH:mm'),
    start_decimal_hour: Math.round((startDt.hour + startDt.minute / 60) * 100) / 100,
    stop_date: stopDt.toFormat('yyyy-MM-dd'),
    stop_time: stopDt.toFormat('HH:mm'),
    stop_decimal_hour: Math.round((stopDt.hour + stopDt.minute / 60) * 100) / 100,
    duration_hhmm: String(hours).padStart(2, '0') + ':' + String(minutes).padStart(2, '0'),
    duration_hours: Math.round((duration / 3600) * 100) / 100,
    tags: (d.tags || []).join(', '),
    month,
  };

  allEntries.push(entry);
  monthsSet.add(month);

  if (!dailyGroups[dateStr]) {
    dailyGroups[dateStr] = {
      date: dateStr,
      project: d.name || 'No project',
      descriptions: [],
      duration_total: 0,
      tags_set: [],
      month,
    };
  }

  if (d.description && !dailyGroups[dateStr].descriptions.includes(d.description)) {
    dailyGroups[dateStr].descriptions.push(d.description);
  }
  dailyGroups[dateStr].duration_total += duration;

  for (const tag of d.tags || []) {
    if (!dailyGroups[dateStr].tags_set.includes(tag)) dailyGroups[dateStr].tags_set.push(tag);
  }
}

allEntries.sort((a, b) => a.start_date.localeCompare(b.start_date) || a.start_time.localeCompare(b.start_time));

const dailySummaries = Object.values(dailyGroups).map((group) => {
  const h = Math.floor(group.duration_total / 3600);
  const m = Math.floor((group.duration_total % 3600) / 60);
  return {
    date: group.date,
    project: group.project,
    description: group.descriptions.join('; '),
    duration_hhmm: String(h).padStart(2, '0') + ':' + String(m).padStart(2, '0'),
    duration_hours: Math.round((group.duration_total / 3600) * 100) / 100,
    tags: group.tags_set.join(', '),
    month: group.month,
  };
});

dailySummaries.sort((a, b) => a.date.localeCompare(b.date));

const months = [...monthsSet].sort();
const staticData = $getWorkflowStaticData('global');
staticData.entries = JSON.stringify(allEntries);
staticData.summaries = JSON.stringify(dailySummaries);
staticData.months = JSON.stringify(months);

return [{ json: { ready: true, months } }];

