const sd = $getWorkflowStaticData('global');
const entries = JSON.parse(sd.entries || '[]');
delete sd.entries;

if (!entries.length) return [{ json: { info: 'No data', entries: [] } }];

const grouped = {};
for (const item of entries) {
  if (!grouped[item.month]) grouped[item.month] = [];
  grouped[item.month].push(item);
}

return Object.keys(grouped)
  .sort()
  .map((month) => ({ json: { month, entries: grouped[month] } }));

